def gen(rng, size):
    n = max(2, size)
    edges = []
    for v in range(2, n + 1):
        u = rng.randrange(1, v)
        w = rng.randrange(1, 10001)
        if rng.random() < 0.5:
            edges.append([u, v, w])
        else:
            edges.append([v, u, w])
    q = max(1, size)
    queries = []
    for _ in range(q):
        if edges and rng.random() < 0.4:
            e = rng.choice(edges)
            queries.append([1, e[0], e[1], rng.randrange(1, 10001)])
        else:
            queries.append([2, rng.randrange(1, n + 1)])
    return [n, edges, queries]

