class Solution:
    def treeQueries(self, n, edges, queries):
        from collections import defaultdict, deque
        adj = defaultdict(dict)
        for u, v, w in edges:
            adj[u][v] = w
            adj[v][u] = w
        ans = []
        for q in queries:
            if q[0] == 1:
                _, u, v, w = q
                adj[u][v] = w
                adj[v][u] = w
            else:
                x = q[1]
                dist = {1: 0}
                dq = deque([1])
                while dq:
                    node = dq.popleft()
                    for nb, w in adj[node].items():
                        if nb not in dist:
                            dist[nb] = dist[node] + w
                            dq.append(nb)
                ans.append(dist[x])
        return ans

