var treeQueries = function(n, edges, queries) {
    const adj = Array.from({length: n + 1}, () => []);
    for (let i = 0; i < edges.length; i++) {
        const [u, v] = edges[i];
        adj[u].push([v, i]);
        adj[v].push([u, i]);
    }
    const tin = new Array(n + 1).fill(0);
    const tout = new Array(n + 1).fill(0);
    const childOfEdge = new Array(Math.max(1, edges.length)).fill(0);
    const weight = edges.map(e => e[2]);
    const visited = new Array(n + 1).fill(false);
    let timer = 1;
    const stack = [[1, false]];
    while (stack.length) {
        const [node, processed] = stack.pop();
        if (processed) { tout[node] = timer - 1; continue; }
        if (visited[node]) continue;
        visited[node] = true;
        tin[node] = timer++;
        stack.push([node, true]);
        for (const [nb, ei] of adj[node]) {
            if (!visited[nb]) {
                childOfEdge[ei] = nb;
                stack.push([nb, false]);
            }
        }
    }
    const size = n + 2;
    const fen = new Array(size + 2).fill(0);
    const add = (i, val) => { for (; i <= size; i += i & (-i)) fen[i] += val; };
    const pointQuery = (i) => { let s = 0; for (; i > 0; i -= i & (-i)) s += fen[i]; return s; };
    const rangeAdd = (l, r, val) => { add(l, val); add(r + 1, -val); };
    for (let ei = 0; ei < edges.length; ei++) {
        const c = childOfEdge[ei];
        rangeAdd(tin[c], tout[c], weight[ei]);
    }
    const edgeIndex = new Map();
    for (let i = 0; i < edges.length; i++) {
        const [u, v] = edges[i];
        edgeIndex.set(u * (n + 1) + v, i);
        edgeIndex.set(v * (n + 1) + u, i);
    }
    const ans = [];
    for (const q of queries) {
        if (q[0] === 1) {
            const u = q[1], v = q[2], w = q[3];
            const ei = edgeIndex.get(u * (n + 1) + v);
            const c = childOfEdge[ei];
            const delta = w - weight[ei];
            weight[ei] = w;
            rangeAdd(tin[c], tout[c], delta);
        } else {
            ans.push(pointQuery(tin[q[1]]));
        }
    }
    return ans;
};
